// Frontend sends { lead: {...}, config: {...} }
const raw = $input.first().json;
const lead = raw.body?.lead ?? raw.lead ?? {};
const config = raw.body?.config ?? raw.config ?? {};

const freq = config.reminders?.frequencyDays ?? 2;
const currentDay = lead.registeredOnDay ?? 0;

return [{
  json: {
    id: lead.id,
    name: lead.name,
    email: (lead.email ?? '').toLowerCase(),
    phone: lead.phone || '',
    company: lead.company || '',
    project_name: lead.projectName || '',
    project_description: lead.projectDescription || '',
    source: lead.source || 'simulator_form',
    budget: lead.formInputs?.budget ?? lead.budget,
    timeline_days: lead.formInputs?.timelineDays ?? lead.timelineDays,
    intent_signal: lead.intentSignal,
    score: lead.score ?? 0,
    classification: lead.classification || 'Pending',
    status: lead.status || 'New',
    reminders_sent: lead.remindersSent ?? 0,
    next_reminder_day: lead.nextReminderDay ?? (currentDay + 1 + freq),
    registered_on_day: currentDay,
    last_action_day: lead.lastActionDay ?? currentDay,
    thread_summary: '',
    assigned_rep: lead.assignedRep,
    created_at: new Date().toISOString()
  }
}];

const lead = $('Build Lead').first().json;
const config = $('Webhook').first().json.body.config || {
  scoring: { budgetWeight: 40, intentWeight: 30, timelineWeight: 30 }
};

const { budgetWeight, intentWeight, timelineWeight } = config.scoring;

const requestBody = {
  model: 'gpt-4o-mini',
  messages: [
    {
      role: 'system',
      content: 'You are a lead scoring engine. Apply the exact formula provided and return ONLY valid JSON. No markdown, no explanation outside the JSON.'
    },
    {
      role: 'user',
      content: `Score this lead 0-10 using these inputs and weights:\n\nBudget: $${lead.budget}\nTimeline: ${lead.timeline_days} days\nIntent signal: ${lead.intent_signal}\n\nScoring rules:\n- budgetScore: budget > 2000 → 10, budget 500-2000 → 6, budget < 500 → 3\n- intentScore: high → 9, medium → 6, low → 3\n- timelineScore: ≤7 days → 10, ≤21 days → 6, >21 days → 3\n\nWeights: Budget ${budgetWeight}%, Intent ${intentWeight}%, Timeline ${timelineWeight}%\n\nFormula: score = round((budgetScore × ${budgetWeight} + intentScore × ${intentWeight} + timelineScore × ${timelineWeight}) / 100)\nClassification: score ≥ 7 = Hot, score 4–6 = Warm, score < 4 = Cold\n\nReturn ONLY this JSON: {"score": <number 0-10>, "classification": "Hot"|"Warm"|"Cold", "rationale": "<one line explaining the score>"}`
    }
  ],
  temperature: 0,
  response_format: { type: 'json_object' }
};

return [{ json: { requestBody } }];

const raw = $input.first().json.choices[0].message.content;
const scoreData = JSON.parse(raw);
const lead = $('Build Lead').first().json;

return [{
  json: {
    score: scoreData.score,
    classification: scoreData.classification,
    rationale: scoreData.rationale,
    // Fields needed to update the row in Sheets
    email: lead.email,
    id: lead.id
  }
}];

const lead = $('Build Lead').first().json;
const scoreData = $('Parse Score').first().json;

const finalLead = {
  ...lead,
  score: scoreData.score,
  classification: scoreData.classification,
  assignedRep: lead.assigned_rep,
  projectName: lead.project_name,
  projectDescription: lead.project_description,
  formInputs: {
    budget: lead.budget,
    timelineDays: lead.timeline_days
  },
  intentSignal: lead.intent_signal,
  registeredOnDay: lead.registered_on_day,
  lastActionDay: lead.last_action_day,
  remindersSent: lead.reminders_sent,
  nextReminderDay: lead.next_reminder_day
};

return [{ json: { lead: finalLead } }];
